def evens(n):
    for i in range(0, n, 2):
        yield i

def odds(n):
    for i in range(1, n, 2):
        yield i

def all_numbers(n):
    # TODO: yield from evens then odds
    for x in evens(n):
        yield x
    for x in odds(n):
        yield x

print(list(all_numbers(6)))

